mapper.select:




			select 
			a.POOL_ID,
			a.VC_ITEM_NAME,
			a.VC_INTER_CODE,
			a.BEG_DATE,
			a.END_DATE,
			a.VC_TRADE_NAME,
			a.VC_TRADE_NO,
			a.VC_SNAME,
			a.VC_DIMENSION_NAME,
			a.VC_CODE,
			a.VC_SCODE,
			a.VC_REASON,
			a.C_DIMENSION_CODE ,
			b.VC_CREDIT_RANK  inner_ranks,t.VC_CREDIT_RANK ranks 

			from V_BSC_POOL a 

    		left join BSC_INNERBONDCREDIT b on b.VC_SCODE = a.VC_SCODE 




				and   B.L_BEGIN_DATE  <=   #{begin_date} 





				and     B.L_END_DATE  >=   #{end_date}



    		join BSC_SECURITY   c on c.VC_SCODE = a.VC_SCODE 

    		left join BSC_INNERINSTITUTIONCREDIT t on c.VC_COMPANY_CODE = t.VC_COMPANY_CODE





				and   t.L_BEGIN_DATE  <=   #{begin_date} 





				and     t.L_END_DATE  >=   #{end_date}


			where 1=1




	                 and  a.POOL_ID in ${pool_id} 






                and  a.VC_INTER_CODE = #{vc_inter_code} 







                and  a.C_DIMENSION_CODE  in

                (

									select C_DIMENSION_CODE from BSC_FILENAME_TYPES where C_DIMENSION_TYPE in ${type}

				) 






                and   a.BEG_DATE    <=   #{begin_date}




                and   a.END_DATE    >=   #{end_date}




                and a.C_DIMENSION_CODE  in   ${dimension}  





			ORDER BY A.C_DIMENSION_CODE,A.VC_TRADE_NO

SELECT A .* FROM V_BSC_POOL_TK A
AND A .POOL_ID = #{pool_id}
AND A .VC_INTER_CODE = #{vc_inter_code}
ORDER BY A.begdate DESC
